2673 static bool isReassociableOp(Instruction *I, unsigned IntOpcode,
2674                              unsigned FPOpcode) {
2675   if (I->getOpcode() == IntOpcode)
2676     return true;
2677   if (I->getOpcode() == FPOpcode && I->hasAllowReassoc() &&
2678       I->hasNoSignedZeros())
